"use client";

import {
  ImageCropper as ArkImageCropper,
  useImageCropper as useArkImageCropper,
} from "@ark-ui/react/image-cropper";
import type React from "react";
import { cn } from "@/lib/utils";

export const useImageCropper = useArkImageCropper;
export const ImageCropperContext = ArkImageCropper.Context;
export const ImageCropperRootProvider = ArkImageCropper.RootProvider;

interface ImageCropperProps
  extends React.ComponentProps<typeof ArkImageCropper.Root> {}

export const ImageCropper = (props: ImageCropperProps) => {
  const { className, ...rest } = props;

  return (
    <ArkImageCropper.Root
      className={cn(
        "relative flex w-full max-w-[28rem] flex-col gap-4 text-foreground",
        "[--cropper-accent:var(--primary)] [--cropper-handler-size:6px] [--cropper-handler-width:3px] [--cropper-line-color:white] [--cropper-line-width:2px] [--cropper-overlay-color:rgb(0_0_0/0.5)]",
        className
      )}
      data-slot="image-cropper"
      {...rest}
    />
  );
};

export const ImageCropperViewport = (
  props: React.ComponentProps<typeof ArkImageCropper.Viewport>
) => {
  const { className, ...rest } = props;

  return (
    <ArkImageCropper.Viewport
      className={cn(
        "relative aspect-video overflow-hidden rounded-lg bg-muted",
        className
      )}
      data-slot="image-cropper-viewport"
      {...rest}
    />
  );
};

export const ImageCropperImage = (
  props: React.ComponentProps<typeof ArkImageCropper.Image>
) => {
  const { className, ...rest } = props;

  return (
    <ArkImageCropper.Image
      className={cn(
        "backface-visibility-hidden pointer-events-none absolute top-0 left-0 h-full w-full select-none object-contain",
        "[transform-origin:center_center]",
        className
      )}
      data-slot="image-cropper-image"
      {...rest}
    />
  );
};

export const ImageCropperSelection = (
  props: React.ComponentProps<typeof ArkImageCropper.Selection>
) => {
  const { className, ...rest } = props;

  return (
    <ArkImageCropper.Selection
      className={cn(
        "box-content",
        "shadow-[0_0_0_9999px_var(--cropper-overlay-color)]",
        "backface-visibility-hidden cursor-move border-2 border-white/50 outline-none",
        "data-[shape=circle]:rounded-full",
        "focus-visible:border-[var(--cropper-accent)]",
        "data-[disabled]:cursor-default",
        "data-[dragging]:cursor-grabbing data-[dragging]:border-white/80",
        className
      )}
      data-slot="image-cropper-selection"
      {...rest}
    />
  );
};

export const ImageCropperHandle = (
  props: React.ComponentProps<typeof ArkImageCropper.Handle>
) => {
  const { className, ...rest } = props;

  return (
    <ArkImageCropper.Handle
      className={cn(
        "absolute flex touch-none items-center justify-center",
        "h-[calc(var(--cropper-handler-size)+8px)] w-[calc(var(--cropper-handler-size)+8px)]",
        "data-[disabled]:hidden",
        "data-[position=ne]:cursor-nesw-resize data-[position=nw]:cursor-nwse-resize",
        "data-[position=se]:cursor-nwse-resize data-[position=sw]:cursor-nesw-resize",
        "data-[position=n]:cursor-ns-resize data-[position=s]:cursor-ns-resize",
        "data-[position=e]:cursor-ew-resize data-[position=w]:cursor-ew-resize",
        "[&[data-position=nw]_*]:size-[var(--cropper-handler-size)] [&[data-position=nw]_*]:border-[var(--cropper-accent)] [&[data-position=nw]_*]:border-t-[length:var(--cropper-handler-width)] [&[data-position=nw]_*]:border-l-[length:var(--cropper-handler-width)] [&[data-position=nw]_*]:bg-popover [&[data-position=nw]_*]:shadow-[0_1px_3px_rgb(0_0_0/0.3)] [&[data-position=nw]_*]:transition-[opacity,transform] [&[data-position=nw]_*]:duration-200 [&[data-position=nw]_*]:ease-[ease] [&[data-position=nw]]:hover:[&_*]:scale-110",
        "[&[data-position=ne]_*]:size-[var(--cropper-handler-size)] [&[data-position=ne]_*]:border-[var(--cropper-accent)] [&[data-position=ne]_*]:border-t-[length:var(--cropper-handler-width)] [&[data-position=ne]_*]:border-r-[length:var(--cropper-handler-width)] [&[data-position=ne]_*]:bg-popover [&[data-position=ne]_*]:shadow-[0_1px_3px_rgb(0_0_0/0.3)] [&[data-position=ne]_*]:transition-[opacity,transform] [&[data-position=ne]_*]:duration-200 [&[data-position=ne]_*]:ease-[ease] [&[data-position=ne]]:hover:[&_*]:scale-110",
        "[&[data-position=se]_*]:size-[var(--cropper-handler-size)] [&[data-position=se]_*]:border-[var(--cropper-accent)] [&[data-position=se]_*]:border-r-[length:var(--cropper-handler-width)] [&[data-position=se]_*]:border-b-[length:var(--cropper-handler-width)] [&[data-position=se]_*]:bg-popover [&[data-position=se]_*]:shadow-[0_1px_3px_rgb(0_0_0/0.3)] [&[data-position=se]_*]:transition-[opacity,transform] [&[data-position=se]_*]:duration-200 [&[data-position=se]_*]:ease-[ease] [&[data-position=se]]:hover:[&_*]:scale-110",
        "[&[data-position=sw]_*]:size-[var(--cropper-handler-size)] [&[data-position=sw]_*]:border-[var(--cropper-accent)] [&[data-position=sw]_*]:border-b-[length:var(--cropper-handler-width)] [&[data-position=sw]_*]:border-l-[length:var(--cropper-handler-width)] [&[data-position=sw]_*]:bg-popover [&[data-position=sw]_*]:shadow-[0_1px_3px_rgb(0_0_0/0.3)] [&[data-position=sw]_*]:transition-[opacity,transform] [&[data-position=sw]_*]:duration-200 [&[data-position=sw]_*]:ease-[ease] [&[data-position=sw]]:hover:[&_*]:scale-110",
        "[&[data-position=n]_*]:size-1.5 [&[data-position=n]_*]:rounded-full [&[data-position=n]_*]:bg-[var(--cropper-accent)] [&[data-position=n]_*]:opacity-0 [&[data-position=n]]:hover:[&_*]:opacity-100",
        "[&[data-position=s]_*]:size-1.5 [&[data-position=s]_*]:rounded-full [&[data-position=s]_*]:bg-[var(--cropper-accent)] [&[data-position=s]_*]:opacity-0 [&[data-position=s]]:hover:[&_*]:opacity-100",
        "[&[data-position=e]_*]:size-1.5 [&[data-position=e]_*]:rounded-full [&[data-position=e]_*]:bg-[var(--cropper-accent)] [&[data-position=e]_*]:opacity-0 [&[data-position=e]]:hover:[&_*]:opacity-100",
        "[&[data-position=w]_*]:size-1.5 [&[data-position=w]_*]:rounded-full [&[data-position=w]_*]:bg-[var(--cropper-accent)] [&[data-position=w]_*]:opacity-0 [&[data-position=w]]:hover:[&_*]:opacity-100",
        className
      )}
      data-slot="image-cropper-handle"
      {...rest}
    >
      <span aria-hidden className="block size-[var(--cropper-handler-size)]" />
    </ArkImageCropper.Handle>
  );
};

export const ImageCropperGrid = (
  props: React.ComponentProps<typeof ArkImageCropper.Grid>
) => {
  const { className, ...rest } = props;

  return (
    <ArkImageCropper.Grid
      className={cn(
        "pointer-events-none absolute opacity-0 transition-opacity duration-200",
        "data-[axis=horizontal]:inset-[33.33%_0] data-[axis=horizontal]:border-white/40 data-[axis=horizontal]:border-t data-[axis=horizontal]:border-b",
        "data-[axis=vertical]:inset-0_[33.33%] data-[axis=vertical]:border-white/40 data-[axis=vertical]:border-r data-[axis=vertical]:border-l",
        "data-[dragging]:opacity-100 data-[panning]:opacity-100",
        className
      )}
      data-slot="image-cropper-grid"
      {...rest}
    />
  );
};
